// client/hooks/useInterval.ts
import { useEffect, useRef } from 'react';
export function useInterval(callback: () => void, delay: number | null, opts: { pauseOnHidden?: boolean } = {}) {
  const cbRef = useRef(callback);
  useEffect(() => { cbRef.current = callback; }, [callback]);
  useEffect(() => {
    if (delay === null) return;
    let intervalId: number | null = null;
    const start = () => { if (intervalId === null) intervalId = window.setInterval(() => cbRef.current(), delay); };
    const stop = () => { if (intervalId !== null) { clearInterval(intervalId); intervalId = null; } };
    if (opts.pauseOnHidden) {
      const onVis = () => { document.hidden ? stop() : start(); };
      document.addEventListener('visibilitychange', onVis);
      if (!document.hidden) start();
      return () => { document.removeEventListener('visibilitychange', onVis); stop(); };
    } else {
      start();
      return stop;
    }
  }, [delay, opts.pauseOnHidden]);
}

