// client/hooks/useHotkey.ts
import { useEffect, useRef } from 'react';
function parse(combo: string) {
  const parts = combo.toLowerCase().split('+').map(p => p.trim());
  return {
    mod: parts.includes('mod') || parts.includes('cmd') || parts.includes('ctrl'),
    shift: parts.includes('shift'),
    alt: parts.includes('alt') || parts.includes('option'),
    key: parts.filter(p => !['mod','cmd','ctrl','shift','alt','option'].includes(p))[0]
  };
}
export function useHotkey(combo: string, handler: (e: KeyboardEvent) => void, opts: { allowInInputs?: boolean; enabled?: boolean } = {}) {
  const handlerRef = useRef(handler);
  useEffect(() => { handlerRef.current = handler; }, [handler]);
  useEffect(() => {
    if (opts.enabled === false) return;
    const { mod, shift, alt, key } = parse(combo);
    const isMac = typeof navigator !== 'undefined' && /Mac/.test(navigator.platform);
    const onKey = (e: KeyboardEvent) => {
      if (!opts.allowInInputs) {
        const t = e.target as HTMLElement;
        if (t?.matches?.('input, textarea, [contenteditable=true]')) return;
      }
      const modPressed = isMac ? e.metaKey : e.ctrlKey;
      if (mod !== modPressed) return;
      if (shift !== e.shiftKey) return;
      if (alt !== e.altKey) return;
      if (e.key.toLowerCase() !== key) return;
      e.preventDefault();
      handlerRef.current(e);
    };
    document.addEventListener('keydown', onKey);
    return () => document.removeEventListener('keydown', onKey);
  }, [combo, opts.allowInInputs, opts.enabled]);
}

