// client/lib/toast.ts
import { createContext, useContext, useReducer, useEffect } from 'react';
type Toast = { id: string; message: string; severity: 'info'|'success'|'warning'|'error'; durationMs: number; action?: { label: string; onClick: () => void } };
const MAX_VISIBLE = 3;
type State = { queue: Toast[]; visible: Toast[] };
type Action = { type: 'add'; toast: Toast } | { type: 'remove'; id: string };
function reducer(state: State, action: Action): State {
  switch (action.type) {
    case 'add': {
      if (state.visible.length < MAX_VISIBLE) return { ...state, visible: [...state.visible, action.toast] };
      return { ...state, queue: [...state.queue, action.toast] };
    }
    case 'remove': {
      const visible = state.visible.filter(t => t.id !== action.id);
      if (state.queue.length && visible.length < MAX_VISIBLE) {
        const [next, ...rest] = state.queue;
        return { visible: [...visible, next], queue: rest };
      }
      return { ...state, visible };
    }
  }
}
const Ctx = createContext<{ add: (t: Omit<Toast, 'id'>) => void; state: State } | null>(null);
export function ToastProvider({ children }: { children: React.ReactNode }) {
  const [state, dispatch] = useReducer(reducer, { queue: [], visible: [] });
  const add = (t: Omit<Toast, 'id'>) => dispatch({ type: 'add', toast: { ...t, id: crypto.randomUUID() } });
  useEffect(() => {
    const timers = state.visible.map(t => setTimeout(() => dispatch({ type: 'remove', id: t.id }), t.durationMs));
    return () => timers.forEach(clearTimeout);
  }, [state.visible]);
  return (
    <Ctx.Provider value={{ add, state }}>
      {children}
      <div aria-live="polite" className="fixed bottom-4 right-4 flex flex-col gap-2 z-50">
        {state.visible.map(t => (
          <div key={t.id} role={t.severity === 'error' ? 'alert' : 'status'} className={`px-4 py-2 rounded shadow-lg ${t.severity === 'error' ? 'bg-red-600 text-white' : 'bg-gray-900 text-white'}`}>
            {t.message}
            {t.action && <button onClick={() => { t.action!.onClick(); dispatch({ type: 'remove', id: t.id }); }} className="ml-2 underline">{t.action.label}</button>}
          </div>
        ))}
      </div>
    </Ctx.Provider>
  );
}
export const useToast = () => { const c = useContext(Ctx); if (!c) throw new Error('No provider'); return c; };
export const toast = {
  info: (msg: string, opts?: Partial<Toast>) => globalToast?.({ message: msg, severity: 'info', durationMs: 4000, ...opts }),
  error: (msg: string, opts?: Partial<Toast>) => globalToast?.({ message: msg, severity: 'error', durationMs: 8000, ...opts })
};
let globalToast: ((t: any) => void) | null = null;

