    if (!tenant?.deletedAt) throw new ConflictError('Not pending deletion');
    tenant.deletedAt = null;
    tenant.scheduledPurgeAt = null;
    await tenant.save();
    logger.warn({ tenantId }, 'tenant_deletion_restored');
  }
};

