// server/services/oauthService.ts
import { encrypt, decrypt } from '../lib/crypto';
import { IntegrationTokenModel } from '../models/IntegrationToken';
export const oauthService = {
  async exchangeCode(provider: string, code: string, state: string) {
    // verify state from session
    const tokens = await fetch(`${PROVIDERS[provider].tokenUrl}`, { method: 'POST', body: new URLSearchParams({ code, client_id: PROVIDERS[provider].clientId, client_secret: PROVIDERS[provider].clientSecret, redirect_uri: `${APP_URL}/oauth/${provider}/callback`, grant_type: 'authorization_code' }) }).then(r => r.json());
    await IntegrationTokenModel.findOneAndUpdate({ userId: currentUser, provider }, {
      accessToken: encrypt(tokens.access_token),
      refreshToken: encrypt(tokens.refresh_token),
      expiresAt: new Date(Date.now() + tokens.expires_in * 1000)
    }, { upsert: true });
  },
  async getValidToken(provider: string, userId: string) {
    const t = await IntegrationTokenModel.findOne({ provider, userId });
    if (!t) throw new NotFoundError('Not connected');
    if (t.expiresAt < new Date(Date.now() + 60000)) {
      const refreshed = await fetch(PROVIDERS[provider].tokenUrl, { method: 'POST', body: new URLSearchParams({ refresh_token: decrypt(t.refreshToken), grant_type: 'refresh_token' }) }).then(r => r.json());
      t.accessToken = encrypt(refreshed.access_token);
      t.expiresAt = new Date(Date.now() + refreshed.expires_in * 1000);
      await t.save();
    }
    return decrypt(t.accessToken);
  }
};

