        {root.descendants().filter(d => d.depth <= (focus?.depth ?? 0) + 1).map((d: any, i) => (
          <circle key={i} cx={d.x} cy={d.y} r={d.r} fill={d.children ? '#e5e7eb' : '#3b82f6'} fillOpacity={0.5} stroke="#9ca3af" onClick={() => d.children && setFocus(d)} />
        ))}
      </Group>
    </svg>
  );
}

