// client/components/TicketRow.tsx
import { useMutation, useQueryClient } from '@tanstack/react-query';
import { Button } from '@tremor/react';
export function TicketRow({ ticket }: any) {
  const qc = useQueryClient();
  const m = useMutation({
    mutationFn: () => fetch(`/api/tickets/${ticket.id}/resolve`, { method: 'POST' }).then(r => { if (!r.ok) throw new Error(); }),
    onMutate: async () => {
      await qc.cancelQueries({ queryKey: ['tickets'] });
      const prev = qc.getQueryData(['tickets']);
      qc.setQueryData(['tickets'], (old: any) => old?.map((t: any) => t.id === ticket.id ? { ...t, resolved: true } : t));
      return { prev };
    },
    onError: (_e, _v, ctx) => qc.setQueryData(['tickets'], ctx?.prev),
    onSettled: () => qc.invalidateQueries({ queryKey: ['tickets'] })
  });
  return <Button onClick={() => m.mutate()} loading={m.isPending}>Resolve</Button>;
}

