import { PieChart, Pie, Cell, Tooltip, ResponsiveContainer } from 'recharts';
import { useMemo, useState } from 'react';
import { OKABE_ITO } from '../lib/palette';
export function Donut({ data }: { data: { name: string; value: number }[] }) {
  const [expanded, setExpanded] = useState(false);
  const total = data.reduce((s, d) => s + d.value, 0);
  const display = useMemo(() => {
    if (expanded) return data;
    const cutoff = total * 0.05;
    const main = data.filter(d => d.value >= cutoff);
    const otherSum = data.filter(d => d.value < cutoff).reduce((s, d) => s + d.value, 0);
    if (otherSum > 0) main.push({ name: 'Other', value: otherSum });
    return main;
  }, [data, expanded, total]);
  return (
    <div className="h-72 relative">
      <ResponsiveContainer><PieChart>
        <Pie data={display} dataKey="value" nameKey="name" innerRadius="60%" outerRadius="80%" onClick={(e: any) => e.name === 'Other' && setExpanded(true)}>
          {display.map((_, i) => <Cell key={i} fill={OKABE_ITO[i % OKABE_ITO.length]} />)}
        </Pie>
        <Tooltip />
      </PieChart></ResponsiveContainer>
      <div className="absolute inset-0 flex items-center justify-center pointer-events-none"><div className="text-center"><div className="text-2xl font-bold">{total.toLocaleString()}</div><div className="text-xs text-gray-500">Total</div></div></div>
