// client/components/UserPicker.tsx
import { useState, useEffect } from 'react';
import { useDebounce } from '../hooks/useDebounce';
export function UserPicker({ onSelect }: { onSelect: (u: any) => void }) {
  const [q, setQ] = useState('');
  const [debQ] = useDebounce(q, { delay: 200 });
  const [results, setResults] = useState<any[]>([]);
  useEffect(() => {
    if (!debQ) return;
    fetch(`/api/users/search?q=${encodeURIComponent(debQ)}`).then(r => r.json()).then(setResults);
  }, [debQ]);
  return (
    <div>
      <input value={q} onChange={e => setQ(e.target.value)} placeholder="Search users" />
      <ul role="listbox">{results.map(u => <li key={u.id} role="option" onClick={() => onSelect(u)}>{u.email}</li>)}</ul>
    </div>
  );
}

